#!/usr/bin/env node
/**
 * BookFactory — suppress-chapter-headers.js
 *
 * Post-processes a PDF generated by Puppeteer/md-to-pdf to remove
 * running headers (and footers) from pages that should not have them:
 *
 *   - Page 1 (title page) — always suppressed
 *   - Page 2 (table of contents) — always suppressed
 *   - Chapter opener pages — detected by text content pattern
 *
 * Professional book standard: running heads are suppressed on all
 * chapter opening pages. Having them is one of the clearest signals
 * of self-published formatting.
 *
 * Usage: node scripts/suppress-chapter-headers.js <pdf-path>
 */

const fs   = require('fs');
const { PDFDocument, rgb } = require('pdf-lib');
const pdfParse = require('pdf-parse');

// ── Chapter opener detection patterns ──────────────────────────────
// Matches the text that appears on chapter opening pages.
// Adjust if your chapter label format changes.
const CHAPTER_OPENER_PATTERN = /\b(introduction|chapter\s+\w+)\b/i;

// ── Pages that are always header-free (0-indexed) ──────────────────
// Title page = 0, TOC = 1 (adjust if TOC spans multiple pages)
const ALWAYS_SUPPRESS = new Set([0, 1]);

async function suppressChapterHeaders(pdfPath) {
  const pdfBytes = fs.readFileSync(pdfPath);

  // ── Step 1: identify chapter opener pages via text extraction ──
  const chapterOpenerPages = new Set([...ALWAYS_SUPPRESS]);

  await pdfParse(pdfBytes, {
    pagerender(pageData) {
      return pageData.getTextContent().then(tc => {
        const text = tc.items.map(i => i.str).join(' ');
        const pageIdx = pageData.pageNumber - 1; // convert 1-indexed → 0-indexed

        if (CHAPTER_OPENER_PATTERN.test(text)) {
          chapterOpenerPages.add(pageIdx);
        }

        return text;
      });
    }
  });

  // ── Step 2: blank header + footer zones on identified pages ──────
  const pdfDoc = await PDFDocument.load(pdfBytes);
  const pages  = pdfDoc.getPages();
  const white  = rgb(1, 1, 1);

  // PDF units: 1 inch = 72 points
  // Our margins: top 0.85in = 61.2pt, bottom 0.85in = 61.2pt
  // Add a small buffer (4pt) to fully cover Puppeteer's header/footer
  const HEADER_HEIGHT = 65;
  const FOOTER_HEIGHT = 65;

  let suppressed = 0;
  for (const pageIdx of chapterOpenerPages) {
    if (pageIdx >= pages.length) continue;

    const page = pages[pageIdx];
    const { width, height } = page.getSize();

    // White rectangle over header zone (top of page)
    page.drawRectangle({
      x: 0,
      y: height - HEADER_HEIGHT,
      width,
      height: HEADER_HEIGHT,
      color: white,
    });

    // White rectangle over footer zone (bottom of page)
    page.drawRectangle({
      x: 0,
      y: 0,
      width,
      height: FOOTER_HEIGHT,
      color: white,
    });

    suppressed++;
  }

  // ── Step 3: save ──────────────────────────────────────────────────
  const modifiedBytes = await pdfDoc.save();
  fs.writeFileSync(pdfPath, modifiedBytes);

  const pageList = [...chapterOpenerPages].sort((a, b) => a - b).map(n => n + 1).join(', ');
  console.log(`  ✓ Header/footer suppressed on ${suppressed} page(s): [${pageList}]`);
}

// ── Entry point ───────────────────────────────────────────────────
const pdfPath = process.argv[2];

if (!pdfPath) {
  console.error('  Usage: node scripts/suppress-chapter-headers.js <pdf-path>');
  process.exit(1);
}

if (!fs.existsSync(pdfPath)) {
  console.error(`  Error: PDF not found at ${pdfPath}`);
  process.exit(1);
}

suppressChapterHeaders(pdfPath).catch(err => {
  console.error(`  ⚠ Header suppression failed: ${err.message}`);
  // Non-fatal — PDF still exists without suppression
  process.exit(0);
});
